import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const ReportIssue = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    type: 'pothole',
    address: '',
    latitude: '',
    longitude: '',
    image: null,
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [preview, setPreview] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    // Get user's current location
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setFormData(prev => ({
            ...prev,
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          }));
        },
        (error) => {
          console.error('Error getting location:', error);
        }
      );
    }
  }, []);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setFormData({
        ...formData,
        image: file,
      });

      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validation
    if (!formData.title.trim()) {
      setError('Title is required');
      setLoading(false);
      return;
    }
    if (!formData.description.trim()) {
      setError('Description is required');
      setLoading(false);
      return;
    }
    if (!formData.address.trim()) {
      setError('Address is required');
      setLoading(false);
      return;
    }
    if (!formData.image) {
      setError('Image is required');
      setLoading(false);
      return;
    }
    if (!formData.latitude || !formData.longitude) {
      setError('Location coordinates are required');
      setLoading(false);
      return;
    }

    const formDataToSend = new FormData();
    formDataToSend.append('title', formData.title.trim());
    formDataToSend.append('description', formData.description.trim());
    formDataToSend.append('type', formData.type);
    formDataToSend.append('address', formData.address.trim());
    formDataToSend.append('latitude', formData.latitude);
    formDataToSend.append('longitude', formData.longitude);
    formDataToSend.append('image', formData.image);

    try {
      console.log('Submitting issue:', {
        title: formData.title,
        description: formData.description,
        type: formData.type,
        address: formData.address,
        latitude: formData.latitude,
        longitude: formData.longitude,
        image: formData.image.name
      });

      const response = await axios.post(
        'http://localhost:3001/api/issues',
        formDataToSend,
        {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        }
      );

      console.log('Issue created successfully:', response.data);
      navigate('/dashboard');
    } catch (error) {
      console.error('Error details:', error.response?.data);
      setError(error.response?.data?.message || error.message || 'Error reporting issue');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-surface text-on-surface antialiased pb-24">
      {/* TopAppBar */}
      <nav className="fixed top-0 w-full z-50 bg-surface/80 dark:bg-slate-900/80 backdrop-blur-xl shadow-sm dark:shadow-none">
        <div className="flex justify-between items-center px-6 py-4 w-full max-w-7xl mx-auto">
          <div className="flex items-center gap-4">
            <button className="text-blue-600 dark:text-blue-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors active:scale-95 duration-200 p-2 rounded-full">
              <span className="material-symbols-outlined">menu</span>
            </button>
            <h1 className="text-xl font-bold tracking-tighter text-slate-900 dark:text-slate-50 font-['Inter']">CivicWatch</h1>
          </div>
          <div className="flex items-center">
            <button className="text-blue-600 dark:text-blue-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors active:scale-95 duration-200 p-2 rounded-full">
              <span className="material-symbols-outlined">notifications</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Main Content Canvas */}
      <main className="pt-20 px-4 max-w-2xl mx-auto space-y-6">
        {/* Page Header */}
        <header className="py-4">
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest text-tertiary mb-1 block">Civic Action</span>
          <h2 className="text-3xl font-extrabold tracking-tight text-on-surface leading-tight">Report New Issue</h2>
          <p className="text-on-surface-variant text-sm mt-2">Provide details about the infrastructure concern in your neighborhood.</p>
        </header>

        {error && (
          <div className="bg-error-container text-on-error-container px-4 py-3 rounded-xl mb-6">
            <div className="flex items-center">
              <span className="material-symbols-outlined mr-2">error</span>
              <div>
                <strong>Error:</strong> {error}
              </div>
            </div>
          </div>
        )}

        {/* Report Form */}
        <section className="space-y-6">
          {/* Image Upload: Bento Style Glass Card */}
          <div className="surface-container-lowest rounded-xl p-1 bg-gradient-to-br from-primary/5 to-transparent shadow-sm">
            <div className="border-2 border-dashed border-outline-variant/30 rounded-lg p-8 flex flex-col items-center justify-center text-center bg-surface-container-lowest/50 backdrop-blur-sm group hover:border-primary transition-colors cursor-pointer">
              <div className="w-16 h-16 rounded-full bg-primary-fixed flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                <span className="material-symbols-outlined text-primary text-3xl">add_a_photo</span>
              </div>
              <p className="font-semibold text-on-surface">Upload Proof</p>
              <p className="text-xs text-on-surface-variant mt-1">Tap to capture or drag photos here</p>
              <input
                type="file"
                name="image"
                accept="image/*"
                onChange={handleImageChange}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              />
            </div>
          </div>

          {preview && (
            <div className="bg-surface-container-lowest rounded-xl p-4">
              <label className="text-xs font-bold uppercase tracking-wider text-on-surface-variant ml-1 block mb-2">Image Preview</label>
              <img
                src={preview}
                alt="Preview"
                className="w-full h-48 object-cover rounded-lg"
              />
            </div>
          )}

          {/* Form Fields */}
          <div className="space-y-4">
            {/* Title Field */}
            <div className="space-y-1.5">
              <label className="text-xs font-bold uppercase tracking-wider text-on-surface-variant ml-1" htmlFor="title">Issue Title</label>
              <input 
                className="w-full px-4 py-3.5 bg-surface-container-lowest rounded-xl border border-outline-variant/20 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all placeholder:text-outline/60 shadow-sm" 
                id="title" 
                placeholder="e.g. Large pothole on 5th Ave" 
                type="text"
                name="title"
                value={formData.title}
                onChange={handleChange}
              />
            </div>

            {/* Category Field */}
            <div className="space-y-1.5">
              <label className="text-xs font-bold uppercase tracking-wider text-on-surface-variant ml-1" htmlFor="type">Category</label>
              <div className="relative">
                <select 
                  className="w-full px-4 py-3.5 bg-surface-container-lowest rounded-xl border border-outline-variant/20 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all appearance-none shadow-sm text-on-surface" 
                  id="type"
                  name="type"
                  value={formData.type}
                  onChange={handleChange}
                >
                  <option value="pothole">Pothole</option>
                  <option value="streetlight">Streetlight</option>
                  <option value="water_leakage">Water Leakage</option>
                  <option value="garbage_overflow">Garbage Overflow</option>
                  <option value="public_property">Public Property</option>
                  <option value="other">Other</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-on-surface-variant">
                  <span className="material-symbols-outlined">expand_more</span>
                </div>
              </div>
            </div>

            {/* Description Field */}
            <div className="space-y-1.5">
              <label className="text-xs font-bold uppercase tracking-wider text-on-surface-variant ml-1" htmlFor="description">Description</label>
              <textarea 
                className="w-full px-4 py-3.5 bg-surface-container-lowest rounded-xl border border-outline-variant/20 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all placeholder:text-outline/60 shadow-sm resize-none" 
                id="description" 
                placeholder="Describe the situation in detail..." 
                rows="4"
                name="description"
                value={formData.description}
                onChange={handleChange}
              />
            </div>

            {/* Map Widget: Location Picker */}
            <div className="space-y-1.5">
              <div className="flex justify-between items-end ml-1">
                <label className="text-xs font-bold uppercase tracking-wider text-on-surface-variant">Incident Location</label>
                <span className="text-[10px] text-primary font-bold flex items-center gap-1">
                  <span className="material-symbols-outlined text-xs">my_location</span> USE GPS
                </span>
              </div>
              <div className="relative w-full h-48 rounded-xl overflow-hidden shadow-md group">
                <img 
                  className="w-full h-full object-cover" 
                  src="https://lh3.googleusercontent.com/aida-public/AB6AXuAlWxZlveADd9CeNEehH-oVBg-qbdjrPnSJFyzB5Po3kzKE0XqxtoUFx2OvmFYIwnZvxey6VeuKh2_cKvDOlhau-eIyl53cL6l0vkxTjqDCIe_x7MKWMjAqHe9uIze6OUje6uYrUrIvJ7mzUK1DJHYOrJw7e2W56qoctrRDvN5oGCZ-H5GkZo1f3qWZDo6r1D7b7KPKLjrz62NGdQDpN5l-SM7gKe5kaqFx4uUmDDAG9ijJGPy3S1MKOckoFEf7Sz4tUQDfVaxuN2A"
                />
                <div className="absolute inset-0 bg-on-surface/5 flex items-center justify-center pointer-events-none">
                  <div className="w-10 h-10 rounded-full bg-primary/20 flex items-center justify-center animate-pulse">
                    <div className="w-4 h-4 bg-primary rounded-full ring-4 ring-white shadow-lg"></div>
                  </div>
                </div>
                <div className="absolute bottom-3 left-3 right-3 bg-surface-container-lowest/90 backdrop-blur-md px-3 py-2 rounded-lg flex items-center gap-2 border border-outline-variant/20">
                  <span className="material-symbols-outlined text-sm text-primary">location_on</span>
                  <span className="text-[11px] font-medium text-on-surface truncate">Scanning street coordinates...</span>
                </div>
              </div>
              <input
                type="text"
                name="address"
                value={formData.address}
                onChange={handleChange}
                placeholder="Enter exact address"
                className="w-full px-4 py-3.5 bg-surface-container-lowest rounded-xl border border-outline-variant/20 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all placeholder:text-outline/60 shadow-sm"
              />
              <div className="grid grid-cols-2 gap-4">
                <input
                  type="number"
                  step="any"
                  name="latitude"
                  value={formData.latitude}
                  onChange={handleChange}
                  placeholder="Latitude"
                  className="w-full px-4 py-3.5 bg-surface-container-lowest rounded-xl border border-outline-variant/20 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all placeholder:text-outline/60 shadow-sm"
                />
                <input
                  type="number"
                  step="any"
                  name="longitude"
                  value={formData.longitude}
                  onChange={handleChange}
                  placeholder="Longitude"
                  className="w-full px-4 py-3.5 bg-surface-container-lowest rounded-xl border border-outline-variant/20 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all placeholder:text-outline/60 shadow-sm"
                />
              </div>
            </div>
          </div>

          {/* Action Button */}
          <div className="pt-4">
            <button 
              onClick={handleSubmit}
              disabled={loading}
              className="w-full bg-gradient-to-r from-primary to-primary-container text-on-primary font-bold py-4 rounded-xl shadow-lg shadow-primary/20 hover:shadow-primary/40 active:scale-[0.98] transition-all flex items-center justify-center gap-3"
            >
              <span className="material-symbols-outlined text-xl">send</span>
              <span>{loading ? 'Submitting...' : 'Submit Report'}</span>
            </button>
            <p className="text-[10px] text-center text-on-surface-variant mt-4 opacity-60">By submitting, you agree to the community guidelines.</p>
          </div>
        </section>
      </main>

      {/* BottomNavBar */}
      <nav className="fixed bottom-0 left-0 w-full flex justify-around items-center px-4 pb-6 pt-3 bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl shadow-[0_-4px_20px_rgba(0,0,0,0.05)] rounded-t-2xl z-50 border-t border-slate-100 dark:border-slate-800">
        {/* Home */}
        <a className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 px-4 py-1 hover:text-blue-500 transition-all active:scale-90 duration-200" href="/">
          <span className="material-symbols-outlined">home</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-1">Home</span>
        </a>
        {/* Map */}
        <a className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 px-4 py-1 hover:text-blue-500 transition-all active:scale-90 duration-200" href="/map">
          <span className="material-symbols-outlined">map</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-1">Map</span>
        </a>
        {/* Report (Active) */}
        <a className="flex flex-col items-center justify-center bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 rounded-xl px-4 py-1 active:scale-90 duration-200" href="#">
          <span className="material-symbols-outlined" style={{fontVariationSettings: "'FILL' 1"}}>add_circle</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-1">Report</span>
        </a>
        {/* Account */}
        <a className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 px-4 py-1 hover:text-blue-500 transition-all active:scale-90 duration-200" href="#">
          <span className="material-symbols-outlined">person</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-1">Account</span>
        </a>
      </nav>
    </div>
  );
};

export default ReportIssue;
